#include <iostream>
using namespace std;

long long a[105][105];
bool vis[105][105];
int cx,cy,zx,zy;
int dx[8]= {2,1,-1,-2,-2,-1, 1, 2};
int dy[8]= {1,2, 2, 1,-1,-2,-2,-1};

int main() {
	cin>>zx>>zy>>cx>>cy;
	vis[cx][cy]=1;
	for(int i=0; i<8; i++) {
		int tx=cx+dx[i],ty=cy+dy[i];
		if(tx>=0 && ty>=0 && tx<=zx && ty<=zy) {
			vis[tx][ty]=1;
		}
	}
	int k=0;
	while(vis[k][0]==0 && k<=zx) {
		a[k][0]=1;
		k++;
	}
	k=0;
	while(vis[0][k]==0 && k<=zy) {
		a[0][k++]=1;
	}
	for(int i=1; i<=zx; i++) {
		for(int j=1; j<=zy; j++) {
			if(vis[i][j]) {
				a[i][j]=0;
			} else {
				a[i][j]=a[i-1][j]+a[i][j-1];
			}
		}
	}
	cout<<a[zx][zy];
	return 0;
}
